@lru_cache(maxsize=32)
def code_tokens_without_comments_or_literals(source: str) -> str:
    output: list[str] = []
    index = 0
    block_comment_depth = 0
    in_line_comment = False
    string_delimiter: str | None = None
    triple_quoted = False

    def hide(value: str) -> None:
        output.extend("\n" if character == "\n" else " " for character in value)

    while index < len(source):
        if in_line_comment:
            character = source[index]
            hide(character)
            index += 1
            if character == "\n":
                in_line_comment = False
            continue

        if block_comment_depth > 0:
            if source.startswith("/*", index):
                hide("/*")
                block_comment_depth += 1
                index += 2
            elif source.startswith("*/", index):
                hide("*/")
                block_comment_depth -= 1
                index += 2
            else:
                hide(source[index])
                index += 1
            continue

        if string_delimiter is not None:
            closing = string_delimiter * (3 if triple_quoted else 1)
            if triple_quoted and source[index] == string_delimiter:
                run_end = index + 1
                while run_end < len(source) and source[run_end] == string_delimiter:
                    run_end += 1
                delimiter_run = source[index:run_end]
                hide(delimiter_run)
                index = run_end
                if len(delimiter_run) >= len(closing):
                    string_delimiter = None
                    triple_quoted = False
            elif source.startswith(closing, index):
                hide(closing)
                index += len(closing)
                string_delimiter = None
                triple_quoted = False
            elif not triple_quoted and source[index] == "\\" and index + 1 < len(source):
                hide(source[index : index + 2])
                index += 2
            else:
                hide(source[index])
                index += 1
            continue

        if source.startswith("//", index):
            hide("//")
            in_line_comment = True
            index += 2
        elif source.startswith("/*", index):
            hide("/*")
            block_comment_depth = 1
            index += 2
        elif source.startswith('"""', index) or source.startswith("'''", index):
            string_delimiter = source[index]
            triple_quoted = True
            hide(source[index : index + 3])
            index += 3
        elif source[index] in {'"', "'"}:
            string_delimiter = source[index]
            triple_quoted = False
            hide(source[index])
            index += 1
        else:
            output.append(source[index])
            index += 1

    return "".join(output)


